// @ts-check
'use strict';

const os = require('os');
const path = require('path');
const fs = require('fs');

// Read the package.json to get Theia frontend config.
// In the packaged app, the package.json is generated by electron-builder with extra metadata.
let config;
try {
  config = require('./package.json').theia.frontend.config;
} catch (err) {
  console.error('[Airone IDE] Failed to read package.json theia config:', err);
  config = {};
}

// `buildDate` is only available in the bundled application (set by electron-builder's extraMetadata).
if (config.buildDate) {
  // `plugins` folder inside Airone IDE. Shipped with VS Code extensions.
  const pluginsPath = path.resolve(__dirname, 'plugins');
  process.env.THEIA_DEFAULT_PLUGINS = `local-dir:${pluginsPath}`;
  // Verify the plugins directory exists
  if (!fs.existsSync(pluginsPath)) {
    console.warn(`[Airone IDE] Plugins directory not found: ${pluginsPath}`);
  }
  // `plugins` folder inside the `~/.aironeIDE` folder. For manually installed VS Code extensions.
  process.env.THEIA_PLUGINS = [
    process.env.THEIA_PLUGINS,
    `local-dir:${path.resolve(os.homedir(), '.aironeIDE', 'plugins')}`,
  ]
    .filter(Boolean)
    .join(',');
}

// Guard: only load the main Electron module if running inside Electron.
// When loaded by electron-builder during packaging (plain Node.js context),
// `process.versions.electron` is undefined. Inside Electron it's set (e.g. "30.1.2").
// This prevents the crash: "Cannot read properties of undefined (reading 'requestSingleInstanceLock')"
if (process.versions.electron) {
  const electronMainPath = path.resolve(__dirname, 'lib', 'backend', 'electron-main');
  if (!fs.existsSync(electronMainPath + '.js')) {
    console.error(`[Airone IDE] CRITICAL: Electron main module not found at: ${electronMainPath}.js`);
    console.error('[Airone IDE] The application cannot start. Please reinstall Airone IDE.');
    process.exit(1);
  }
  require('./lib/backend/electron-main');
} else {
  console.warn('[Airone IDE] Not running inside Electron (process.versions.electron is undefined). Skipping electron-main load.');
}
